import java.util.Scanner;
import java.util.Arrays;

public class SecureBuffer {
    public static void main(String[] args) {
        Scanner scanner = new Scanner(System.in);

        System.out.print("Enter a string: ");
        String userInput = scanner.nextLine(); // Use nextLine() to read the entire line

        // Define a maximum buffer size
        int maxBufferSize = 10;

        if (userInput.length() > maxBufferSize) {
            System.out.println("Input exceeds maximum buffer size. Please enter a shorter string.");
            return;
        }

        byte[] buffer = new byte[maxBufferSize];

        // Copy user input into buffer
        Arrays.fill(buffer, (byte) 0); // Fill buffer with zeros to avoid leaking sensitive information
        System.arraycopy(userInput.getBytes(), 0, buffer, 0, userInput.length());

        System.out.println("User input copied into buffer successfully.");
    }
}

### Explanation:
취약유형: Buffer Overflow
